import TronWeb from 'tronweb';

// TRONGRID CONFIGURATION
const TRONGRID_API_KEY = 'c91bd6bb-7cc8-49c8-a185-63eeaa684010';
const FULL_NODE = 'https://api.trongrid.io';
const USDT_CONTRACT_ADDRESS = 'TXLAQ63Xg1NAzckPwKHvzw7CSEmLMEqcdj'; // Provided by user
const DECIMALS = 6;

// Helper to safely get TronWeb instance
const getSafeTronWeb = (privateKey?: string) => {
  try {
    return new TronWeb({
      fullHost: FULL_NODE,
      headers: { 'TRON-PRO-API-KEY': TRONGRID_API_KEY },
      privateKey: privateKey || '01'.repeat(32) // Dummy key if none provided
    });
  } catch (e) {
    console.error("TronWeb initialization failed:", e);
    return null;
  }
};

/**
 * Generate a new TRC20 wallet for a user.
 * Includes a fallback to a simulation address if TronWeb fails.
 */
export const generateUserWallet = async () => {
  try {
    const tronWeb = getSafeTronWeb();
    if (tronWeb) {
      // createAccount is synchronous in newer TronWeb, but we await just in case
      return await tronWeb.createAccount();
    }
    throw new Error("TronWeb instance not available");
  } catch (error) {
    console.warn("Blockchain Service Unavailable. Generating fallback simulation wallet.", error);
    // Return a valid-looking structure so the app doesn't crash during demo/dev
    const randomHex = Array.from({length: 32}, () => Math.floor(Math.random() * 16).toString(16)).join('');
    return {
      address: {
        base58: 'T' + Array.from({length: 33}, () => 'ABCDEF1234567890'[Math.floor(Math.random() * 16)]).join(''),
        hex: '41' + randomHex
      },
      privateKey: randomHex + randomHex
    };
  }
};

/**
 * Scans for USDT transfers to a specific address using TronGrid.
 * Used for the Automatic Deposit Confirmation system.
 */
export const checkUsdtDeposits = async (address: string, sinceTimestamp: number) => {
  try {
    const url = `${FULL_NODE}/v1/accounts/${address}/transactions/trc20?limit=20&contract_address=${USDT_CONTRACT_ADDRESS}&only_to=true&min_timestamp=${sinceTimestamp}`;
    const response = await fetch(url, {
      headers: { 'TRON-PRO-API-KEY': TRONGRID_API_KEY }
    });
    const data = await response.json();

    if (data.success && data.data) {
      return data.data.map((tx: any) => ({
        hash: tx.transaction_id,
        from: tx.from,
        amount: Number(tx.value) / Math.pow(10, DECIMALS),
        timestamp: tx.block_timestamp
      }));
    }
    return [];
  } catch (error) {
    console.error('TronGrid API Error:', error);
    return [];
  }
};

/**
 * Process a Withdrawal from the Hot Wallet to a user.
 */
export const processUsdtWithdrawal = async (
  hotWalletPrivateKey: string,
  toAddress: string,
  amount: number
) => {
  const tronWeb = getSafeTronWeb(hotWalletPrivateKey);

  if (!tronWeb) {
    throw new Error("Blockchain bridge currently unavailable. Please try again later.");
  }

  try {
    const contract = await tronWeb.contract().at(USDT_CONTRACT_ADDRESS);
    const amountInSun = Math.floor(amount * Math.pow(10, DECIMALS));

    // Call the transfer(address, uint256) function
    const txHash = await contract.transfer(toAddress, amountInSun.toString()).send();

    return {
      success: true,
      txHash
    };
  } catch (error: any) {
    console.error('Withdrawal Failed:', error);
    throw new Error(error.message || 'Blockchain transaction failed');
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { 
  onAuthStateChanged, 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-auth.js';
import { 
  doc, 
  onSnapshot, 
  collection, 
  query, 
  where 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js';
import { auth, db } from './firebase.ts';
import { 
  AppState, 
  User, 
  TransactionType, 
  TransactionStatus, 
  Transaction, 
  UserPackage 
} from './types.ts';
import { 
  createFirestoreUser, 
  purchasePackageFirestore,
  processDailyRoiFirestore,
  updateUserProfileFirestore,
  syncUserDepositsFirestore,
  requestWithdrawalFirestore
} from './store.ts';
import Layout from './components/Layout.tsx';
import Dashboard from './components/Dashboard.tsx';
import Wallet from './components/Wallet.tsx';
import AdminPanel from './components/AdminPanel.tsx';
import Profile from './components/Profile.tsx';
import QuantumAnalyst from './components/QuantumAnalyst.tsx';
import { INITIAL_PACKAGES, REF_LEVELS } from './constants.tsx';
import { motion, AnimatePresence } from 'framer-motion';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activePackages, setActivePackages] = useState<UserPackage[]>([]);
  const [platformSettings, setPlatformSettings] = useState<AppState['platformSettings']>({
    isRoiEnabled: true,
    referralLevels: REF_LEVELS,
    minWithdrawal: 10,
    platformPaused: false
  });

  const [view, setView] = useState<string>('auth');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [refCode, setRefCode] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [isProvisioning, setIsProvisioning] = useState(false);
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');
  const [authError, setAuthError] = useState<string | null>(null);

  const handleManualProvision = useCallback(async () => {
    if (!auth.currentUser) return;
    setIsProvisioning(true);
    setAuthError(null);
    try {
      await createFirestoreUser(auth.currentUser.uid, auth.currentUser.email || '', refCode);
      // Success will be picked up by onSnapshot
    } catch (err: any) {
      console.error("Manual provision failed", err);
      setAuthError(`Manual provision failure: ${err.message}`);
      setIsProvisioning(false);
    }
  }, [refCode]);

  // Unified Protocol Synchronization
  useEffect(() => {
    let unsubUser: (() => void) | null = null;
    let unsubTx: (() => void) | null = null;
    let unsubPk: (() => void) | null = null;

    const unsubscribeAuth = onAuthStateChanged(auth, async (firebaseUser) => {
      setAuthError(null);
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();

      if (firebaseUser) {
        setIsLoading(true);
        // Subscribe to User Profile
        const userRef = doc(db, 'users', firebaseUser.uid);
        unsubUser = onSnapshot(userRef, async (docSnap) => {
          if (docSnap.exists()) {
            const userData = { ...docSnap.data(), id: docSnap.id } as User;
            setCurrentUser(userData);
            setIsProvisioning(false);
            setIsLoading(false);
            if (view === 'auth') setView('dashboard');
          } else {
            console.log("No profile found. Attempting auto-provision...");
            setIsProvisioning(true);
            setIsLoading(false);

            // Auto-attempt provision if it's missing (self-healing)
            try {
              await createFirestoreUser(firebaseUser.uid, firebaseUser.email || '', '');
            } catch (err) {
              console.warn("Auto-provision failed, waiting for manual trigger", err);
            }
          }
        }, (err) => {
          console.error("Profile sync failure:", err);
          setAuthError("Failed to sync profile data. Check connection.");
          setIsLoading(false);
        });

        // Subscribe to Transactions
        unsubTx = onSnapshot(query(collection(db, 'transactions'), where('userId', '==', firebaseUser.uid)), (snap) => {
          const txs = snap.docs.map(d => ({ ...d.data(), id: d.id }) as Transaction);
          setTransactions(txs.sort((a, b) => b.timestamp - a.timestamp));
        });

        // Subscribe to Staking Nodes
        unsubPk = onSnapshot(query(collection(db, 'activePackages'), where('userId', '==', firebaseUser.uid)), (snap) => {
          setActivePackages(snap.docs.map(d => ({ ...d.data(), id: d.id }) as UserPackage));
        });

      } else {
        setCurrentUser(null);
        setTransactions([]);
        setActivePackages([]);
        setView('auth');
        setIsLoading(false);
        setIsProvisioning(false);
      }
    });

    return () => {
      unsubscribeAuth();
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();
    };
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setAuthError(null);
    try {
      await signInWithEmailAndPassword(auth, email, password);
    } catch (error: any) {
      setAuthError(error.message);
      setIsLoading(false);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setIsProvisioning(true);
    setAuthError(null);
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, password);
      // Explicit profile creation
      await createFirestoreUser(cred.user.uid, email, refCode);
    } catch (error: any) {
      console.error("Registration Error", error);
      setAuthError(error.message);
      setIsLoading(false);
      setIsProvisioning(false);
      // If registration failed halfway, ensure we are signed out so user can try again
      if (auth.currentUser) await signOut(auth);
    }
  };

  const handleLogout = async () => {
    try {
      setIsLoading(true);
      await signOut(auth);
    } catch (err: any) {
      console.error("Session termination error:", err);
      setIsLoading(false);
    }
  };

  const handleWithdrawal = async (amount: number, address: string) => {
    if (!currentUser) return;
    if (amount < platformSettings.minWithdrawal) {
      alert(`Minimum extraction is $${platformSettings.minWithdrawal} USDT`);
      return;
    }
    try {
