import React, { useState, useEffect, useCallback } from 'react';
import { 
  onAuthStateChanged, 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-auth.js';
import { 
  doc, 
  onSnapshot, 
  collection, 
  query, 
  where 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js';
import { auth, db } from './firebase.ts';
import { 
  AppState, 
  User, 
  TransactionType, 
  TransactionStatus, 
  Transaction, 
  UserPackage 
} from './types.ts';
import { 
  createFirestoreUser, 
  purchasePackageFirestore,
  processDailyRoiFirestore,
  updateUserProfileFirestore,
  syncUserDepositsFirestore,
  requestWithdrawalFirestore
} from './store.ts';
import Layout from './components/Layout.tsx';
import Dashboard from './components/Dashboard.tsx';
import Wallet from './components/Wallet.tsx';
import AdminPanel from './components/AdminPanel.tsx';
import Profile from './components/Profile.tsx';
import { INITIAL_PACKAGES, REF_LEVELS } from './constants.tsx';
import { motion, AnimatePresence } from 'framer-motion';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activePackages, setActivePackages] = useState<UserPackage[]>([]);
  const [platformSettings, setPlatformSettings] = useState<AppState['platformSettings']>({
    isRoiEnabled: true,
    referralLevels: REF_LEVELS,
    minWithdrawal: 10,
    platformPaused: false
  });

  const [view, setView] = useState<string>('auth');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [refCode, setRefCode] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [isProvisioning, setIsProvisioning] = useState(false);
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');
  const [authError, setAuthError] = useState<string | null>(null);

  const handleManualProvision = useCallback(async () => {
    if (!auth.currentUser) return;
    setIsProvisioning(true);
    setAuthError(null);
    try {
      await createFirestoreUser(auth.currentUser.uid, auth.currentUser.email || '', refCode);
      // Success will be picked up by onSnapshot
    } catch (err: any) {
      console.error("Manual provision failed", err);
      setAuthError(`Manual provision failure: ${err.message}`);
      setIsProvisioning(false);
    }
  }, [refCode]);

  // Unified Protocol Synchronization
  useEffect(() => {
    let unsubUser: (() => void) | null = null;
    let unsubTx: (() => void) | null = null;
    let unsubPk: (() => void) | null = null;

    const unsubscribeAuth = onAuthStateChanged(auth, async (firebaseUser) => {
      setAuthError(null);
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();

      if (firebaseUser) {
        setIsLoading(true);
        // Subscribe to User Profile
        const userRef = doc(db, 'users', firebaseUser.uid);
        unsubUser = onSnapshot(userRef, async (docSnap) => {
          if (docSnap.exists()) {
            const userData = { ...docSnap.data(), id: docSnap.id } as User;
            setCurrentUser(userData);
            setIsProvisioning(false);
            setIsLoading(false);
            if (view === 'auth') setView('dashboard');
          } else {
            console.log("No profile found. Attempting auto-provision...");
            setIsProvisioning(true);
            setIsLoading(false);

            // Auto-attempt provision if it's missing (self-healing)
            try {
              await createFirestoreUser(firebaseUser.uid, firebaseUser.email || '', '');
            } catch (err) {
              console.warn("Auto-provision failed, waiting for manual trigger", err);
            }
          }
        }, (err) => {
          console.error("Profile sync failure:", err);
          setAuthError("Failed to sync profile data. Check connection.");
          setIsLoading(false);
        });

        // Subscribe to Transactions
        unsubTx = onSnapshot(query(collection(db, 'transactions'), where('userId', '==', firebaseUser.uid)), (snap) => {
          const txs = snap.docs.map(d => ({ ...d.data(), id: d.id }) as Transaction);
          setTransactions(txs.sort((a, b) => b.timestamp - a.timestamp));
        });

        // Subscribe to Staking Nodes
        unsubPk = onSnapshot(query(collection(db, 'activePackages'), where('userId', '==', firebaseUser.uid)), (snap) => {
          setActivePackages(snap.docs.map(d => ({ ...d.data(), id: d.id }) as UserPackage));
        });

      } else {
        setCurrentUser(null);
        setTransactions([]);
        setActivePackages([]);
        setView('auth');
        setIsLoading(false);
        setIsProvisioning(false);
      }
    });

    return () => {
      unsubscribeAuth();
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();
    };
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setAuthError(null);
    try {
      await signInWithEmailAndPassword(auth, email, password);
    } catch (error: any) {
      setAuthError(error.message);
      setIsLoading(false);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setIsProvisioning(true);
    setAuthError(null);
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, password);
      // Explicit profile creation
      await createFirestoreUser(cred.user.uid, email, refCode);
    } catch (error: any) {
      console.error("Registration Error", error);
      setAuthError(error.message);
      setIsLoading(false);
      setIsProvisioning(false);
      // If registration failed halfway, ensure we are signed out so user can try again
      if (auth.currentUser) await signOut(auth);
    }
  };

  const handleLogout = async () => {
    try {
      setIsLoading(true);
      await signOut(auth);
    } catch (err: any) {
      console.error("Session termination error:", err);
      setIsLoading(false);
    }
  };

  const handleWithdrawal = async (amount: number, address: string) => {
    if (!currentUser) return;
    if (amount < platformSettings.minWithdrawal) {
      alert(`Minimum extraction is $${platformSettings.minWithdrawal} USDT`);
      return;
    }
    try {
      await requestWithdrawalFirestore(currentUser.id, amount, address);
      alert('Withdrawal request initialized. Blockchain authorization pending.');
    } catch (err: any) {
      alert(err.message);
    }
  };

  const handleDepositSync = async () => {
    if (!currentUser) return;
    try {
      await syncUserDepositsFirestore(currentUser.id);
      alert('Network synchronization complete. TRC20 deposits verified.');
    } catch (err: any) {
      alert('Sync Failed: ' + err.message);
    }
  };

  const handlePurchase = async (pkgId: string) => {
    if (!currentUser) return;
    const pkg = INITIAL_PACKAGES.find(p => p.id === pkgId);
    if (!pkg) return;
    if (currentUser.capitalBalance < pkg.minAmount) {
      alert(`Insufficient Capital. Required: ${pkg.minAmount} USDT`);
      setView('wallet');
      return;
    }
    if (confirm(`Activate node cluster: ${pkg.name}?`)) {
      try {
        await purchasePackageFirestore(currentUser.id, pkgId);
        alert('Staking node active.');
      } catch (err: any) {
        alert(err.message);
      }
    }
  };

  // UI State: Loading or Provisioning
  if (isLoading || (auth.currentUser && !currentUser)) {
    return (
      <div className="min-h-screen bg-black flex items-center justify-center">
        <div className="flex flex-col items-center gap-6">
          <div className="w-12 h-12 border-4 border-white/20 border-t-white rounded-full animate-spin"></div>
          <div className="text-center space-y-4 max-w-xs">
            <p className="text-[10px] font-black uppercase tracking-[0.5em] text-white/40 animate-pulse">
              {isProvisioning ? 'Securing Cryptographic Identity' : 'Syncing Distributed Ledger'}
            </p>
