                         <p className="text-[10px] md:text-sm font-medium leading-tight opacity-60 group-hover:opacity-100">{pkg.description}</p>
                         <div className="mt-auto space-y-4 pt-6">
                           <div className="flex justify-between border-b border-app-border group-hover:border-app-accent-text/10">
                             <span className="text-[8px] font-bold uppercase opacity-60">Entry</span>
                             <span className="text-[10px] font-bold mono">${pkg.minAmount}</span>
                           </div>
                           <button onClick={() => handlePurchase(pkg.id)} className="w-full py-3 border text-[8px] font-black uppercase tracking-[0.2em] border-app-border group-hover:bg-app-accent-text group-hover:text-app-accent group-hover:border-app-accent-text">Initialize</button>
                         </div>
                       </div>
                     </div>
                   );
                 })}
               </div>
            </div>
          )}
          {view === 'referrals' && (
            <div className="space-y-24 max-w-7xl mx-auto">
               <div className="flex flex-col lg:flex-row justify-between items-end gap-12">
                  <div className="space-y-6 flex-1">
                    <h1 className="text-6xl lg:text-9xl font-black uppercase tracking-tighter leading-[0.85] text-app-text">Affiliate<br/>Network.</h1>
                    <p className="serif italic text-2xl text-app-muted max-w-xl">Earn passive yield from network growth across 3 tiers of depth.</p>
                  </div>
                  <div className="w-full lg:w-96 p-10 bg-app-accent text-app-accent-text space-y-6">
                    <p className="text-[10px] font-black uppercase tracking-widest">Global Invite Link</p>
                    <p className="text-xl font-black mono tracking-widest truncate">{currentUser.referralCode}</p>
                    <button onClick={() => { navigator.clipboard.writeText(currentUser.referralCode); alert('Identity link secured.'); }} className="w-full py-3 bg-app-accent-text text-app-accent text-[10px] font-black uppercase tracking-[0.2em]">Copy Identity</button>
                  </div>
               </div>
            </div>
          )}
          {view === 'profile' && <Profile user={currentUser} onUpdate={(data) => updateUserProfileFirestore(currentUser.id, data)} />}
          {view === 'admin' && (
            <AdminPanel 
              state={{ currentUser, users: [], packages: INITIAL_PACKAGES, activePackages, transactions, platformSettings }}
              onUpdateSettings={(s) => setPlatformSettings(prev => ({...prev, ...s}))}
              onTriggerRoi={async () => { await processDailyRoiFirestore(platformSettings); alert('Network cycle processed.'); }}
              onManageWithdrawal={() => {}}
            />
          )}
        </motion.div>
      </AnimatePresence>
    </Layout>
  );
};

