  const [activePackages, setActivePackages] = useState<UserPackage[]>([]);
  const [platformSettings, setPlatformSettings] = useState<AppState['platformSettings']>({
    isRoiEnabled: true,
    referralLevels: REF_LEVELS,
    minWithdrawal: 10,
    platformPaused: false
  });

  const [view, setView] = useState<string>('auth');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [refCode, setRefCode] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [isProvisioning, setIsProvisioning] = useState(false);
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');
  const [authError, setAuthError] = useState<string | null>(null);

  const handleManualProvision = useCallback(async () => {
    if (!auth.currentUser) return;
    setIsProvisioning(true);
    setAuthError(null);
    try {
      await createFirestoreUser(auth.currentUser.uid, auth.currentUser.email || '', refCode);
    } catch (err: any) {
      console.error("Manual provision failed", err);
      setAuthError(`Setup failed: ${err.message}`);
      setIsProvisioning(false);
    }
  }, [refCode]);

  useEffect(() => {
    let unsubUser: (() => void) | null = null;
    let unsubTx: (() => void) | null = null;
    let unsubPk: (() => void) | null = null;

    const unsubscribeAuth = onAuthStateChanged(auth, async (firebaseUser) => {
      setAuthError(null);
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();

      if (firebaseUser) {
        setIsLoading(true);
        const userRef = doc(db, 'users', firebaseUser.uid);
        unsubUser = onSnapshot(userRef, async (docSnap) => {
          if (docSnap.exists()) {
            const userData = { ...docSnap.data(), id: docSnap.id } as User;
            setCurrentUser(userData);
            setIsProvisioning(false);
            setIsLoading(false);
            if (view === 'auth') setView('dashboard');
          } else {
            console.log("No profile found. Attempting auto-provision...");
            setIsProvisioning(true);
            setIsLoading(false);
            try {
              await createFirestoreUser(firebaseUser.uid, firebaseUser.email || '', '');
            } catch (err) {
              console.warn("Auto-provision failed, waiting for manual trigger", err);
            }
          }
        }, (err) => {
          console.error("Profile sync failure:", err);
          setAuthError("Failed to load profile. Check connection.");
          setIsLoading(false);
        });

        unsubTx = onSnapshot(query(collection(db, 'transactions'), where('userId', '==', firebaseUser.uid)), (snap) => {
          const txs = snap.docs.map(d => ({ ...d.data(), id: d.id }) as Transaction);
          setTransactions(txs.sort((a, b) => b.timestamp - a.timestamp));
        });

        unsubPk = onSnapshot(query(collection(db, 'activePackages'), where('userId', '==', firebaseUser.uid)), (snap) => {
          setActivePackages(snap.docs.map(d => ({ ...d.data(), id: d.id }) as UserPackage));
        });

      } else {
        setCurrentUser(null);
        setTransactions([]);
        setActivePackages([]);
        setView('auth');
        setIsLoading(false);
        setIsProvisioning(false);
      }
    });

    return () => {
      unsubscribeAuth();
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();
    };
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setAuthError(null);
    try {
      await signInWithEmailAndPassword(auth, email, password);
    } catch (error: any) {
      setAuthError(error.message);
      setIsLoading(false);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setIsProvisioning(true);
    setAuthError(null);
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, password);
      await createFirestoreUser(cred.user.uid, email, refCode);
    } catch (error: any) {
      console.error("Registration Error", error);
      setAuthError(error.message);
      setIsLoading(false);
      setIsProvisioning(false);
      if (auth.currentUser) await signOut(auth);
    }
  };

  const handleLogout = async () => {
    try {
      setIsLoading(true);
      await signOut(auth);
    } catch (err: any) {
      console.error("Session termination error:", err);
      setIsLoading(false);
    }
  };

  const handleWithdrawal = async (amount: number, address: string) => {
    if (!currentUser) return;
    if (amount < platformSettings.minWithdrawal) {
      alert(`Minimum withdrawal is $${platformSettings.minWithdrawal} USDT`);
      return;
    }
    try {
      await requestWithdrawalFirestore(currentUser.id, amount, address);
      alert('Withdrawal request submitted. Waiting for approval.');
    } catch (err: any) {
      alert(err.message);
    }
  };

  const handleDepositSync = async () => {
    if (!currentUser) return;
    try {
      await syncUserDepositsFirestore(currentUser.id);
      alert('Deposit check complete. Your balance has been updated.');
    } catch (err: any) {
      alert('Sync Failed: ' + err.message);
    }
  };

  const handlePurchase = async (pkgId: string) => {
    if (!currentUser) return;
    const pkg = INITIAL_PACKAGES.find(p => p.id === pkgId);
    if (!pkg) return;
    if (currentUser.capitalBalance < pkg.minAmount) {
      alert(`Insufficient Balance. Required: ${pkg.minAmount} USDT`);
      setView('wallet');
      return;
    }
    if (confirm(`Start staking with: ${pkg.name}?`)) {
      try {
        await purchasePackageFirestore(currentUser.id, pkgId);
        alert('Staking plan activated successfully.');
      } catch (err: any) {
        alert(err.message);
      }
    }
  };

  if (isLoading || (auth.currentUser && !currentUser)) {
    return (
      <div className="min-h-screen bg-app-bg flex items-center justify-center">
        <div className="flex flex-col items-center gap-6">
          <div className="w-12 h-12 border-4 border-app-border border-t-app-accent rounded-full animate-spin"></div>
          <div className="text-center space-y-4 max-w-xs">
            <p className="text-[10px] font-black uppercase tracking-[0.5em] text-app-muted animate-pulse">
              {isProvisioning ? 'Creating Account...' : 'Loading...'}
            </p>
            {authError && <p className="text-[9px] text-red-500 font-bold uppercase tracking-widest">{authError}</p>}
            {isProvisioning && (
              <div className="flex flex-col gap-4 pt-8">
                 <button 
                  onClick={handleManualProvision}
                  className="px-6 py-2 border border-app-border text-[8px] font-black uppercase tracking-widest text-app-muted hover:text-app-text hover:border-app-text transition-all"
                >
                  Retry Setup
                </button>
                <button 
                  onClick={handleLogout}
                  className="text-[8px] font-black uppercase tracking-widest text-app-muted/50 hover:text-app-text transition-colors"
                >
                  Cancel
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-app-bg flex flex-col lg:flex-row relative transition-colors duration-300">
        <div className="flex-1 p-12 lg:p-24 flex flex-col justify-between border-r border-app-border">
          <div className="flex items-center gap-4">
             <div className="w-8 h-8 bg-app-accent"></div>
             <span className="text-2xl font-black uppercase tracking-tighter text-app-text">QUANTUM</span>
          </div>
          <div className="max-w-xl space-y-12">
            <motion.h1 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="text-7xl lg:text-9xl font-black tracking-tighter leading-[0.85] uppercase text-app-text"
            >
              Start <br/> <span className="text-app-muted">Earning.</span>
            </motion.h1>
            <p className="serif italic text-2xl text-app-muted leading-relaxed">
              Professional USDT Staking Platform. Simple, secure, and profitable.
            </p>
          </div>
          <div className="flex gap-16">
            <div className="space-y-1">
              <p className="text-2xl font-black mono tracking-tighter text-app-text">LIVE</p>
              <p className="text-[10px] font-bold text-app-muted uppercase tracking-widest">System Online</p>
            </div>
          </div>
        </div>
        <div className="w-full lg:w-[35%] min-h-screen bg-app-bg flex items-center justify-center p-12 lg:p-24 transition-colors duration-300">
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="w-full max-sm space-y-12">
            <div>
              <h2 className="text-[10px] font-black uppercase tracking-[0.5em] text-app-muted mb-2">Welcome</h2>
              <p className="text-2xl font-bold tracking-tight text-app-text">{authMode === 'login' ? 'Log In' : 'Create Account'}</p>
            </div>
            {authError && (
              <div className="p-4 bg-red-500/10 border border-red-500/20 text-red-500 text-[10px] font-bold uppercase tracking-widest">
                {authError}
              </div>
            )}
            <form className="space-y-8" onSubmit={authMode === 'login' ? handleLogin : handleRegister}>
              <div className="space-y-2 group">
                <p className="text-[10px] font-black uppercase tracking-widest text-app-muted group-focus-within:text-app-text transition-colors">Email</p>
                <input type="email" required value={email} onChange={(e) => setEmail(e.target.value)} className="w-full bg-transparent border-b border-app-border py-3 outline-none focus:border-app-text transition-colors font-medium text-app-text placeholder:text-app-muted/30" placeholder="name@email.com" />
              </div>
              <div className="space-y-2 group">
                <p className="text-[10px] font-black uppercase tracking-widest text-app-muted group-focus-within:text-app-text transition-colors">Password</p>
                <input type="password" required value={password} onChange={(e) => setPassword(e.target.value)} className="w-full bg-transparent border-b border-app-border py-3 outline-none focus:border-app-text transition-colors font-medium text-app-text placeholder:text-app-muted/30" placeholder="••••••••" />
              </div>
              {authMode === 'register' && (
                <div className="space-y-2 group">
                  <p className="text-[10px] font-black uppercase tracking-widest text-app-muted">Referral Code (Optional)</p>
                  <input type="text" value={refCode} onChange={(e) => setRefCode(e.target.value)} className="w-full bg-transparent border-b border-app-border py-3 outline-none focus:border-app-text transition-colors font-mono text-xs uppercase text-app-text placeholder:text-app-muted/30" placeholder="CODE" />
                </div>
              )}
              <button type="submit" disabled={isLoading} className="w-full py-5 bg-app-accent text-app-accent-text text-xs font-black uppercase tracking-[0.3em] hover:opacity-90 active:scale-[0.98] transition-all flex items-center justify-center gap-4">
                {isLoading ? <div className="w-4 h-4 border-2 border-app-accent-text/20 border-t-app-accent-text rounded-full animate-spin"></div> : (authMode === 'login' ? 'Log In' : 'Sign Up')}
              </button>
              <div className="text-center pt-4">
                 <button type="button" onClick={() => { setAuthMode(authMode === 'login' ? 'register' : 'login'); setAuthError(null); }} className="text-[10px] font-black uppercase tracking-widest text-app-muted hover:text-app-text transition-colors">{authMode === 'login' ? "Create an Account" : "Back to Login"}</button>
              </div>
            </form>
          </motion.div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout} onNavigate={setView} currentView={view}>
      <AnimatePresence mode="wait">
        <motion.div key={view} initial={{ opacity: 0, y: 5 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -5 }} transition={{ duration: 0.3 }} className="pb-24 lg:pb-0">
          {view === 'dashboard' && <Dashboard user={currentUser} transactions={transactions} activePackages={activePackages} />}
          {view === 'wallet' && <Wallet user={currentUser} onDepositSim={handleDepositSync} onWithdrawRequest={handleWithdrawal} />}
          {view === 'packages' && (
            <div className="space-y-12 max-w-7xl mx-auto">
               <div className="flex flex-col gap-4">
                  <h2 className="text-5xl lg:text-9xl font-black uppercase tracking-tighter leading-none text-app-text">Staking<br/>Plans.</h2>
                  <p className="serif italic text-xl lg:text-2xl text-app-muted max-w-xl">Choose a plan to start earning daily rewards.</p>
               </div>
               <div className="grid grid-cols-2 md:grid-cols-3 border-t border-l border-app-border">
                 {INITIAL_PACKAGES.map((pkg) => {
                   const activeCount = activePackages.filter(ap => ap.packageId === pkg.id && ap.isActive).length;
                   return (
                     <div key={pkg.id} className="border-r border-b border-app-border p-6 md:p-12 group transition-all duration-500 hover:bg-app-accent hover:text-app-accent-text">
                       <div className="space-y-4 md:space-y-8 h-full flex flex-col">
                         <div className="flex justify-between items-start">
                           <h3 className="text-[10px] md:text-xs font-black uppercase tracking-[0.2em]">{pkg.name}</h3>
                           {activeCount > 0 && <span className="text-[8px] font-black uppercase px-2 py-0.5 bg-app-accent text-app-accent-text group-hover:bg-app-accent-text group-hover:text-app-accent">Active (x{activeCount})</span>}
                         </div>
                         <div className="space-y-1">
                           <p className="text-3xl md:text-6xl font-black mono tracking-tighter leading-none">{pkg.dailyRoi}%</p>
                           <p className="text-[8px] font-black uppercase tracking-widest opacity-60">Daily Return</p>
                         </div>
                         <p className="text-[10px] md:text-sm font-medium leading-tight opacity-60 group-hover:opacity-100">{pkg.description}</p>
                         <div className="mt-auto space-y-4 pt-6">
                           <div className="flex justify-between border-b border-app-border group-hover:border-app-accent-text/10">
                             <span className="text-[8px] font-bold uppercase opacity-60">Min Deposit</span>
                             <span className="text-[10px] font-bold mono">${pkg.minAmount}</span>
                           </div>
                           <button onClick={() => handlePurchase(pkg.id)} className="w-full py-3 border text-[8px] font-black uppercase tracking-[0.2em] border-app-border group-hover:bg-app-accent-text group-hover:text-app-accent group-hover:border-app-accent-text">Activate Plan</button>
                         </div>
                       </div>
                     </div>
                   );
                 })}
               </div>
            </div>
          )}
          {view === 'referrals' && (
            <div className="space-y-24 max-w-7xl mx-auto">
               <div className="flex flex-col lg:flex-row justify-between items-end gap-12">
                  <div className="space-y-6 flex-1">
                    <h1 className="text-6xl lg:text-9xl font-black uppercase tracking-tighter leading-[0.85] text-app-text">Referral<br/>Program.</h1>
                    <p className="serif italic text-2xl text-app-muted max-w-xl">Earn rewards by inviting friends to the platform.</p>
                  </div>
                  <div className="w-full lg:w-96 p-10 bg-app-accent text-app-accent-text space-y-6">
                    <p className="text-[10px] font-black uppercase tracking-widest">Your Invite Code</p>
                    <p className="text-xl font-black mono tracking-widest truncate">{currentUser.referralCode}</p>
                    <button onClick={() => { navigator.clipboard.writeText(currentUser.referralCode); alert('Code copied to clipboard.'); }} className="w-full py-3 bg-app-accent-text text-app-accent text-[10px] font-black uppercase tracking-[0.2em]">Copy Code</button>
                  </div>
               </div>
            </div>
          )}
          {view === 'profile' && <Profile user={currentUser} onUpdate={(data) => updateUserProfileFirestore(currentUser.id, data)} />}
          {view === 'admin' && (
            <AdminPanel 
              state={{ currentUser, users: [], packages: INITIAL_PACKAGES, activePackages, transactions, platformSettings }}
              onUpdateSettings={(s) => setPlatformSettings(prev => ({...prev, ...s}))}
              onTriggerRoi={async () => { await processDailyRoiFirestore(platformSettings); alert('Daily rewards paid out successfully.'); }}
              onManageWithdrawal={() => {}}
            />
          )}
        </motion.div>
      </AnimatePresence>
    </Layout>
  );
};

