               </div>
            </div>
          )}
          {view === 'profile' && <Profile user={displayUser} onUpdate={(data) => updateUserProfileFirestore(displayUser.id, data)} />}
          {view === 'admin' && (
            <AdminPanel 
              state={{ currentUser: displayUser, users: [], packages: INITIAL_PACKAGES, activePackages, transactions, platformSettings }}
              onUpdateSettings={(s) => setPlatformSettings(prev => ({...prev, ...s}))}
              onTriggerRoi={async () => { await processDailyRoiFirestore(platformSettings); alert('Daily rewards paid out successfully.'); }}
              onManageWithdrawal={() => {}}
            />
          )}
        </motion.div>
      </AnimatePresence>
    </Layout>
  );
};

